import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getStaff, updateStaff } from "../../api/adminUserApi";
import { getAuth } from "../../utils/auth";

export default function EditStaff() {
  const { id } = useParams();
  const navigate = useNavigate();

  const { role } = getAuth();
  const isAdmin = role === "admin";

  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState(null);

  const [form, setForm] = useState({
    role: "staff",
    isDeleted: false,
  });

  useEffect(() => {
    const load = async () => {
      try {
        // Backend has only GET /api/admin-users (not /:id)
        // So we fetch all and find by id
        const res = await getStaff();
        const found = (res.data || []).find((u) => u._id === id);

        if (!found) {
          alert("User not found");
          return navigate("/admin/staff");
        }

        setUser(found);
        setForm({
          role: found.role || "staff",
          isDeleted: !!found.isDeleted,
        });
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load user");
        navigate("/admin/staff");
      } finally {
        setLoading(false);
      }
    };

    if (isAdmin) load();
    else setLoading(false);
  }, [id, navigate, isAdmin]);

  const submit = async (e) => {
    e.preventDefault();
    try {
      await updateStaff(id, form);
      alert("Updated!");
      navigate("/admin/staff");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  if (!isAdmin) return <div style={{ padding: 20 }}>Access denied</div>;
  if (loading) return <div style={{ padding: 20 }}>Loading...</div>;

  return (
    <div style={{ padding: 20, maxWidth: 520 }}>
      <h2>Edit User</h2>

      {user && (
        <div style={{ marginBottom: 12, padding: 10, border: "1px solid #ddd", borderRadius: 8 }}>
          <div><b>Name:</b> {user.name}</div>
          <div><b>Email:</b> {user.email}</div>
        </div>
      )}

      <form onSubmit={submit}>
        <label>Role</label>
        <select
          value={form.role}
          onChange={(e) => setForm((p) => ({ ...p, role: e.target.value }))}
          style={{ width: "100%", padding: 10, marginTop: 6 }}
        >
          <option value="staff">Staff</option>
          <option value="manager">Manager</option>
          <option value="admin">Admin</option>
          <option value="user">User</option>
        </select>

        <div style={{ marginTop: 12 }}>
          <label style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <input
              type="checkbox"
              checked={form.isDeleted}
              onChange={(e) => setForm((p) => ({ ...p, isDeleted: e.target.checked }))}
            />
            Deactivated (isDeleted)
          </label>
        </div>

        <div style={{ marginTop: 14, display: "flex", gap: 10 }}>
          <button type="submit" style={{ padding: "10px 14px" }}>Save</button>
          <button type="button" onClick={() => navigate("/admin/staff")} style={{ padding: "10px 14px" }}>
            Cancel
          </button>
        </div>
      </form>
    </div>
  );
}
